#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int son[4],fail,nxt,len;
}tr[N];

int T,n,a[N],tot,f[N],ans;
char s[N];

int New(){
    tot++;
    tr[tot].son[0]=tr[tot].son[1]=tr[tot].son[2]=tr[tot].son[3]=0;
    tr[tot].fail=tr[tot].len=0;
    return tot;
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%s",s+1);
        n=strlen(s+1);
        ans=n;
        for(int i=1;i<=n;i++){
            if(s[i]=='A') a[i]=0;
            if(s[i]=='C') a[i]=1;
            if(s[i]=='G') a[i]=2;
            if(s[i]=='T') a[i]=3;
        }
        tot=0;
        New();
        f[1]=1;
        a[0]=-1;
        for(int i=1,p=1;i<=n;i++){
            while(p>1 && a[i]!=a[i-tr[p].len-1]) p=tr[p].fail;
            if(a[i]!=a[i-tr[p].len-1]) continue;
            //printf("p %d %d\n",i,p);
            if(!tr[p].son[a[i]]){
                //puts("add");
                tr[p].son[a[i]]=New();
                //printf("%d\n",tot);
                tr[tot].len=tr[p].len+2;
                int u=tr[p].fail;
                while(u && a[i]!=a[i-tr[u].len-1]) u=tr[u].fail;
                if(!u) tr[tot].fail=1;
                else tr[tot].fail=tr[u].son[a[i]];
                u=tr[p].nxt;
                while(u && (a[i]!=a[i-tr[u].len-1] || tr[u].len*2+4>tr[tot].len)) u=tr[u].fail;
                if(!u) tr[tot].nxt=1;
                else tr[tot].nxt=tr[u].son[a[i]];
                f[tot]=min(f[p]+1,f[tr[tot].nxt]+tr[tot].len/2-tr[tr[tot].nxt].len+1);
                ans=min(ans,f[tot]+n-tr[tot].len);
                //printf("%d %d %d\n",tr[tot].len,f[tot],tr[tr[tot].nxt].len);
            }
            p=tr[p].son[a[i]];
            //printf("to %d %d\n",i,p);
        }
        printf("%d\n",ans);
    }
    return 0;
}
